spec.setup_code:
return {
  draw: function(ctx, W, H, t, dt) {
    // Background
    ctx.fillStyle = '#111827';
    ctx.fillRect(0, 0, W, H);

    var duration = 12000;
    var progress = (t % duration) / duration;

    var stage = 1;
    if (progress >= 0.25 && progress < 0.50) stage = 2;
    else if (progress >= 0.50 && progress < 0.75) stage = 3;
    else if (progress >= 0.75) stage = 4;

    var midY = H / 2 - 30;
    var boxAX = W / 2 - 60;
    var boxBX = W / 2 + 60;

    // Draw Box A (Medium)
    ctx.fillStyle = '#F59E0B';
    ctx.fillRect(boxAX - 16, midY - 24, 32, 48);
    ctx.strokeStyle = '#D97706';
    ctx.lineWidth = 1.5;
    ctx.strokeRect(boxAX - 16, midY - 24, 32, 48);

    ctx.fillStyle = '#FFFFFF';
    ctx.font = 'bold 8px -apple-system, sans-serif';
    ctx.textAlign = 'center';
    ctx.fillText('CEREAL', boxAX, midY - 6);
    ctx.fillText('10 oz', boxAX, midY + 6);
    ctx.fillText('$4.00', boxAX, midY + 16);

    ctx.fillStyle = '#9CA3AF';
    ctx.font = '9px monospace';
    ctx.fillText('Box A', boxAX, midY - 34);

    // Draw Box B (Large)
    ctx.fillStyle = '#8B5CF6';
    ctx.fillRect(boxBX - 20, midY - 30, 40, 60);
    ctx.strokeStyle = '#7C3AED';
    ctx.strokeRect(boxBX - 20, midY - 30, 40, 60);

    ctx.fillStyle = '#FFFFFF';
    ctx.font = 'bold 9px -apple-system, sans-serif';
    ctx.fillText('CEREAL', boxBX, midY - 10);
    ctx.fillText('20 oz', boxBX, midY + 4);
    ctx.fillText('$6.00', boxBX, midY + 16);

    ctx.fillStyle = '#9CA3AF';
    ctx.font = '9px monospace';
    ctx.fillText('Box B', boxBX, midY - 40);

    // Stage highlights and unit price calculations
    ctx.font = 'bold 11px monospace';
    ctx.textAlign = 'center';

    if (stage >= 2) {
      ctx.fillStyle = '#F59E0B';
      ctx.fillText('$4.00 / 10 oz = $0.40/oz', boxAX, midY + 42);
    }

    if (stage >= 3) {
      ctx.fillStyle = '#8B5CF6';
      ctx.fillText('$6.00 / 20 oz = $0.30/oz', boxBX, midY + 42);
    }

    if (stage === 4) {
      // Draw green check box outline on Box B
      ctx.strokeStyle = '#10B981';
      ctx.lineWidth = 2.5;
      ctx.strokeRect(boxBX - 23, midY - 33, 46, 66);

      ctx.fillStyle = '#10B981';
      ctx.fillText('BEST BUY!', boxBX, midY - 48);
    }

    // Bottom text explanations
    ctx.font = 'bold 15px -apple-system, sans-serif';
    ctx.fillStyle = '#F3F4F6';

    if (stage === 1) {
      ctx.fillText('Unit Price Comparison', W / 2, H - 42);
      ctx.font = '11px -apple-system, sans-serif';
      ctx.fillStyle = '#9CA3AF';
      ctx.fillText('Which cereal box gives you more food for your money?', W / 2, H - 22);
    } else if (stage === 2) {
      ctx.fillStyle = '#F59E0B';
      ctx.fillText('Calculate Box A Unit Price', W / 2, H - 42);
      ctx.font = '11px -apple-system, sans-serif';
      ctx.fillStyle = '#9CA3AF';
      ctx.fillText('Divide: $4.00 by 10 ounces to find price per ounce ($0.40).', W / 2, H - 22);
    } else if (stage === 3) {
      ctx.fillStyle = '#8B5CF6';
      ctx.fillText('Calculate Box B Unit Price', W / 2, H - 42);
      ctx.font = '11px -apple-system, sans-serif';
      ctx.fillStyle = '#9CA3AF';
      ctx.fillText('Divide: $6.00 by 20 ounces to find price per ounce ($0.30).', W / 2, H - 22);
    } else {
      ctx.fillStyle = '#10B981';
      ctx.fillText('Box B is the Best Value', W / 2, H - 42);
      ctx.font = '11px -apple-system, sans-serif';
      ctx.fillStyle = '#9CA3AF';
      ctx.fillText('$0.30/oz is cheaper than $0.40/oz. You save $0.10 per ounce!', W / 2, H - 22);
    }
  }
};
